#include <bits/stdc++.h>
using namespace std;

const int N=310,mod=1e9+7;

int n,m,t,d[N][N];

void add(int &x,int y){
    x=(x+y)%mod;
}

int qpow(int a,int b){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%mod;
        base=base*base%mod,b>>=1;
    }
    return ans;
}

int main(){
    scanf("%d%d%d",&n,&m,&t);
    for(int i=1;i<=m;i++){
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        if(!t){
            add(d[u][u],w);
            add(d[v][v],w);
            add(d[u][v],mod-w);
            add(d[v][u],mod-w);
        }else{
            add(d[v][v],w);
            add(d[u][v],mod-w);
        }
    }
    for(int i=2;i<=n;i++){
        if(!d[i][i])
            for(int j=i+1;j<=n;j++)
                if(d[j][i]){
                    for(int k=2;k<=n;k++){
                        d[j][k]=mod-d[j][k];
                        swap(d[i][k],d[j][k]);
                    }
                    break;
                }
        if(!d[i][i]) break;
        int num;
        for(int j=i+1;j<=n;j++){
            num=1ll*d[j][i]*qpow(d[i][i],mod-2)%mod;
            for(int k=i;k<=n;k++)
                add(d[j][k],mod-1ll*num*d[i][k]%mod);
        }
    }
    int res=1;
    for(int i=2;i<=n;i++)
        res=1ll*res*d[i][i]%mod;
    printf("%d",res);
    return 0;
}
